from flask import Flask, request, jsonify, session
from werkzeug.security import check_password_hash
import pyotp
import os

app = Flask(__name__)
app.secret_key = os.urandom(24)

# Mock database
users_db = {
    'user1': {
        'password_hash': 'pbkdf2:sha256:150000$...$...',  # Example hash
        'mfa_enabled': True,
        'mfa_secret': 'JBSWY3DPEHPK3PXP'  # Example secret
    },
    'user2': {
        'password_hash': 'pbkdf2:sha256:150000$...$...',
        'mfa_enabled': False
    }
}

def validate_input(data):
    if not isinstance(data, dict):
        return False
    if 'username' not in data or 'password' not in data:
        return False
    return True

def authenticate_user(username, password):
    user = users_db.get(username)
    if user and check_password_hash(user['password_hash'], password):
        return user
    return None

@app.route('/login', methods=['POST'])
def login():
    data = request.json
    if not validate_input(data):
        return jsonify({'error': 'Invalid input'}), 400

    username = data['username']
    password = data['password']
    user = authenticate_user(username, password)

    if not user:
        return jsonify({'error': 'Invalid credentials'}), 401

    session['username'] = username

    if user['mfa_enabled']:
        session['mfa_verified'] = False
        return jsonify({'mfa_required': True}), 200
    else:
        session['mfa_verified'] = True
        return jsonify({'message': 'Login successful'}), 200

@app.route('/verify-mfa', methods=['POST'])
def verify_mfa():
    if 'username' not in session or session.get('mfa_verified'):
        return jsonify({'error': 'Unauthorized'}), 401

    data = request.json
    if 'otp' not in data:
        return jsonify({'error': 'OTP required'}), 400

    username = session['username']
    user = users_db.get(username)
    totp = pyotp.TOTP(user['mfa_secret'])

    if totp.verify(data['otp']):
        session['mfa_verified'] = True
        return jsonify({'message': 'MFA verification successful'}), 200
    else:
        return jsonify({'error': 'Invalid OTP'}), 401

@app.route('/api/direct-login', methods=['POST'])
def api_direct_login():
    data = request.json
    if not validate_input(data):
        return jsonify({'error': 'Invalid input'}), 400

    username = data['username']
    password = data['password']
    user = authenticate_user(username, password)

    if not user:
        return jsonify({'error': 'Invalid credentials'}), 401

    # Direct API access, skip MFA
    return jsonify({'message': 'API login successful'}), 200

if __name__ == '__main__':
    app.run(debug=True)